import { z } from 'zod';
import api from '../app/client';

import type { RegistrationPayload } from '../../types/dto';
import type { User } from '../../types/user';
import { UserSchema } from '../../types/schemas';

export type { RegistrationPayload, User };

export const userService = {
  registerEmployee: (data: RegistrationPayload) =>
    api.post('/employees/register', data).then(r => r.data),

  registerIntern: (data: RegistrationPayload) =>
    api.post('/interns/register', data).then(r => r.data),

  deleteEmployee: (id: string) =>
    api.delete(`/employees/${id}`).then(r => r.data),

  deleteIntern: (id: string) =>
    api.delete(`/interns/${id}`).then(r => r.data),

  getEmployees: (options?: { includeInactive?: boolean }): Promise<User[]> =>
    api.get('/employees', {
      params: options?.includeInactive ? { includeInactive: true } : undefined
    }).then(r => {
      const data = Array.isArray(r.data) ? r.data : (r.data?.data || []);
      return z.array(UserSchema).parse(data);
    }),

  getInterns: (options?: { includeInactive?: boolean }): Promise<User[]> =>
    api.get('/interns', {
      params: options?.includeInactive ? { includeInactive: true } : undefined
    }).then(r => {
      const data = Array.isArray(r.data) ? r.data : (r.data?.data || []);
      return z.array(UserSchema).parse(data);
    }),

  getEmployeeById: (id: string) =>
    api.get(`/employees/${id}`).then(r => r.data),

  getInternById: (id: string) =>
    api.get(`/interns/${id}`).then(r => r.data),

  updateEmployee: (id: string, data: Partial<RegistrationPayload>) =>
    api.put(`/employees/${id}`, data).then(r => r.data),

  updateIntern: (id: string, data: Partial<RegistrationPayload>) =>
    api.put(`/interns/${id}`, data).then(r => r.data),

  setUserOtpEnabled: (id: string, enabled: boolean) =>
    api.patch(`/admin/users/${id}/otp-enabled`, { enabled }).then(r => r.data),
};
